from pet_class import Petdef main():    print("Enter Your Pet's Details")    name = input("Enter the pet's name: ")    animal_type = input("Enter the type of animal (e.g., Dog, Cat, Bird): ")    while True:        try:            age = int(input("Enter the pet's age: "))            break        except ValueError:            print("Please enter a valid integer for the age.")    my_pet = Pet(name, animal_type, age)    my_pet.set_name(name)    my_pet.set_animal_type(animal_type)    my_pet.set_age(age)    print("\n Pet Information Summary ")    print(f"Pet Name:    {my_pet.get_name()}")    print(f"Animal Type: {my_pet.get_animal_type()}")    print(f"Pet Age:     {my_pet.get_age()} years old")if __name__ == "__main__":    main()